import React, { createContext, useState, useEffect, useContext, useCallback } from 'react';
import axios from 'axios';
import { useAuth } from './AuthContext';

const CartContext = createContext();

function unwrapCartPayload(res) {
  const data = res?.data?.data;
  if (!data) return { items: [], totals: null, coupon: null };
  return {
    items: Array.isArray(data.items) ? data.items : [],
    totals: data.totals || null,
    coupon: data.coupon || null,
    discountAmount: Number(data.discountAmount) || 0
  };
}

function apiErrorMessage(error, fallback) {
  const d = error.response?.data;
  return d?.message || d?.error || fallback;
}

export const useCart = () => {
  const context = useContext(CartContext);
  if (!context) {
    throw new Error('useCart must be used within CartProvider');
  }
  return context;
};

export const CartProvider = ({ children }) => {
  const { user, loading: authLoading } = useAuth();
  const [cartState, setCartState] = useState({
    items: [],
    totals: null,
    coupon: null,
    discountAmount: 0
  });
  const [loading, setLoading] = useState(true);

  const fetchCart = useCallback(async () => {
    try {
      const response = await axios.get('/api/cart', {
        withCredentials: true
      });
      setCartState(unwrapCartPayload(response));
    } catch (error) {
      console.error('Error fetching cart:', error);
      setCartState({
        items: [],
        totals: null,
        coupon: null,
        discountAmount: 0
      });
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    if (authLoading) return;
    setLoading(true);
    fetchCart();
  }, [authLoading, user?.id, fetchCart]);

  const addToCart = async (product, quantity = 1) => {
    const ref = product?._id || product?.productId || product?.slug;
    if (!ref) {
      return { success: false, error: 'Invalid product' };
    }
    try {
      await axios.post(
        '/api/cart/add',
        {
          productId: String(ref),
          quantity
        },
        { withCredentials: true }
      );
      await fetchCart();
      return { success: true };
    } catch (error) {
      return {
        success: false,
        error: apiErrorMessage(error, 'Failed to add to cart')
      };
    }
  };

  const updateCartItem = async (productRef, quantity) => {
    try {
      await axios.put(
        '/api/cart/update',
        {
          productId: String(productRef),
          quantity
        },
        { withCredentials: true }
      );
      await fetchCart();
      return { success: true };
    } catch (error) {
      return {
        success: false,
        error: apiErrorMessage(error, 'Failed to update cart')
      };
    }
  };

  const removeFromCart = async (productRef) => {
    try {
      await axios.delete(
        `/api/cart/remove/${encodeURIComponent(productRef)}`,
        { withCredentials: true }
      );
      await fetchCart();
      return { success: true };
    } catch (error) {
      return {
        success: false,
        error: apiErrorMessage(error, 'Failed to remove from cart')
      };
    }
  };

  const clearCart = async () => {
    try {
      await axios.delete('/api/cart/clear', {
        withCredentials: true
      });
      await fetchCart();
      return { success: true };
    } catch (error) {
      return {
        success: false,
        error: apiErrorMessage(error, 'Failed to clear cart')
      };
    }
  };

  const applyCoupon = async (code) => {
    try {
      await axios.post(
        '/api/cart/coupon',
        { code: String(code || '').trim() },
        { withCredentials: true }
      );
      await fetchCart();
      return { success: true };
    } catch (error) {
      return {
        success: false,
        error: apiErrorMessage(error, 'Invalid coupon')
      };
    }
  };

  const removeCoupon = async () => {
    try {
      await axios.delete('/api/cart/coupon', { withCredentials: true });
      await fetchCart();
      return { success: true };
    } catch (error) {
      return {
        success: false,
        error: apiErrorMessage(error, 'Could not remove coupon')
      };
    }
  };

  const getCartCount = () =>
    cartState.items.reduce((sum, line) => sum + (line.quantity || 0), 0);

  const getCartTotal = () => {
    if (cartState.totals && Number.isFinite(Number(cartState.totals.total))) {
      return Number(cartState.totals.total);
    }
    return cartState.items.reduce(
      (sum, line) => sum + (line.lineTotal ?? (line.price || 0) * (line.quantity || 0)),
      0
    );
  };

  const getSubtotal = () => {
    if (cartState.totals && Number.isFinite(Number(cartState.totals.itemsSubtotal))) {
      return Number(cartState.totals.itemsSubtotal);
    }
    return cartState.items.reduce(
      (sum, line) => sum + (line.lineTotal ?? (line.price || 0) * (line.quantity || 0)),
      0
    );
  };

  return (
    <CartContext.Provider
      value={{
        cart: cartState.items,
        cartState,
        loading,
        addToCart,
        updateCartItem,
        removeFromCart,
        clearCart,
        applyCoupon,
        removeCoupon,
        getCartCount,
        getCartTotal,
        getSubtotal,
        fetchCart
      }}
    >
      {children}
    </CartContext.Provider>
  );
};
